"""
concurrent_triage: leader/follower 分组并发研判 + dedup_key 缓存复用（自包含）。

去重模式：
  1. 输入 alerts 先按 dedup_key 分组 → unique dedup_keys 列表
  2. 每个 group 只对 leader（首条）做研判；followers 复用 leader 结果，不重复调 LLM
  3. 无 dedup_key 的 alert 各自独立成 work unit（防御性研判，无法复用）

并发结构：
  外层 ThreadPoolExecutor(max_workers=concurrency)：处理 unique work unit
    （concurrency 取值 1–5，默认 1，由 inputs.concurrency 控制）
  内层 ThreadPoolExecutor(max_workers=4)：单条 alert 内 4 个 LLM 并行
    （survey / cve_related / cve_info / payload_analysis — 保留 tdp_alert_triage
     的 4 并行分支结构）
  稳态 LLM 并发峰值 ≈ concurrency × 4（仅 4 并行分支阶段，且分支全部启用时）

研判产物只以字段形式附加到每条 alert（attack_verdict / risk_level /
report_title / triage_report ...），**不生成任何独立的 per-alert markdown 报告
文件**，避免冗余落盘与跨日期路径失效。

dedup_key 缓存（与 stream_alert_denoise 的 LSH 状态文件同根目录，逻辑独立）：
  ~/.flocks/workspace/workflows/stream_alert_triage/triage_cache.pkl
  - cache 命中：直接复用历史 verdict/title/triage_report，**不调用 LLM**
  - cache 未命中：leader 执行完整内联研判（情报 + 4 并行 LLM + verdict + title + report）；
                  follower 直接广播 leader 结果
  - 新结果合并写回 cache，FIFO LRU 淘汰，文件锁 + 原子落盘
"""

import ipaddress
import json
import os
import pickle
import re
import sys
import threading
import time
from concurrent.futures import ThreadPoolExecutor, as_completed

IS_WINDOWS = sys.platform == 'win32'
if IS_WINDOWS:
    import msvcrt  # noqa: F401
else:
    import fcntl   # noqa: F401

WORKFLOW_NAME = 'stream_alert_triage'

# Per-call LLM timeout and retry budget for every analysis branch in this
# node. Workflow LLM calls share the dedicated ``flocks-workflow-llm-loop``;
# a single hung call (e.g. provider 504, slow TLS handshake) without a
# timeout would otherwise pin one of the (already concurrency-limited)
# worker threads for up to httpx's DEFAULT read timeout (10 min), serially
# blocking the rest of the alert pipeline. 120s + 1 retry covers normal
# slow-but-alive responses while still recovering from transient hangs.
LLM_CALL_TIMEOUT_S = 120.0
LLM_CALL_MAX_RETRIES = 1

TRIAGE_FIELDS = (
    'attack_verdict',
    'risk_level',
    'report_title',
    'triage_report',
    'attack_success',
)
VERDICT_LABELS = ('attack_success', 'attack_failed', 'attack', 'unknown', 'benign')
VERDICT_RISK = {
    'attack_success': 'High',
    'attack_failed':  'Medium',
    'attack':         'Medium',
    'unknown':        'Medium',
    'benign':         'Low',
}
VERDICT_CN = {
    'attack_success': '攻击成功',
    'attack_failed':  '攻击失败',
    'attack':         '攻击',
    'unknown':        '未知',
    'benign':         '安全',
}
TRIAGE_REPORT_VERSION = 'soc.triage.markdown.v1'
TRIAGE_REPORT_TAGS = (
    'report_title',
    'report_meta',
    'analysis_steps',
    'triage_conclusion',
    'attack_payload',
    'payload_explanation',
    'response_evidence',
    'key_evidence',
    'disposal_recommendation',
)


# ── Cache persistence ─────────────────────────────────────────────────────────

def _cache_paths():
    from flocks.config import Config
    flocks_root = Config().get_global().data_dir.parent
    state_dir = flocks_root / 'workspace' / 'workflows' / WORKFLOW_NAME
    state_dir.mkdir(parents=True, exist_ok=True)
    return str(state_dir / 'triage_cache.pkl'), str(state_dir / 'triage_cache.lock')


def _acquire_lock(lock_path):
    fh = open(lock_path, 'w+')
    try:
        if IS_WINDOWS:
            fh.write('L'); fh.flush(); fh.seek(0)
            while True:
                try:
                    msvcrt.locking(fh.fileno(), msvcrt.LK_LOCK, 1); break
                except OSError:
                    continue
        else:
            fcntl.flock(fh.fileno(), fcntl.LOCK_EX)
    except BaseException:
        try:
            fh.close()
        except Exception:
            pass
        raise
    return fh


def _release_lock(fh):
    try:
        if IS_WINDOWS:
            try:
                fh.seek(0); msvcrt.locking(fh.fileno(), msvcrt.LK_UNLCK, 1)
            except OSError:
                pass
        else:
            fcntl.flock(fh.fileno(), fcntl.LOCK_UN)
    finally:
        fh.close()


def _load_cache(cache_path):
    if not os.path.exists(cache_path) or os.path.getsize(cache_path) == 0:
        return {}
    try:
        with open(cache_path, 'rb') as f:
            c = pickle.load(f)
        if not isinstance(c, dict):
            return {}
        print(f'[triage_cache] loaded {len(c)} entries from {cache_path}')
        return c
    except Exception as e:
        print(f'[triage_cache] WARNING: failed to load ({e}), starting fresh')
        return {}


def _save_cache_atomic(cache_path, cache):
    tmp = cache_path + '.tmp'
    try:
        with open(tmp, 'wb') as f:
            pickle.dump(cache, f); f.flush(); os.fsync(f.fileno())
        os.replace(tmp, cache_path)
        print(f'[triage_cache] saved {len(cache)} entries -> {cache_path}')
    except Exception as e:
        print(f'[triage_cache] WARNING: failed to save: {e}')
        if os.path.exists(tmp):
            try: os.remove(tmp)
            except Exception: pass


def _evict_lru(cache, max_keys):
    excess = len(cache) - max_keys
    if excess > 0:
        for k in list(cache.keys())[:excess]:
            del cache[k]
        return excess
    return 0


# ── Runtime output config and persistence targets ──────────────────────────────
#
# Defaults are read from ~/.flocks/plugins/workflows/stream_alert_triage/config.json.
# Runtime inputs override config values. The default mode is soc_db so SOC pages
# read the same DB-backed dataset. JSONL remains available via config/input:
#   triage_output_mode = soc_db | jsonl | both | none
#   persist_triage_output = true  (legacy alias that adds JSONL to soc_db)

import datetime as _datetime

MAX_RECORDS_PER_FILE = 10000
_TRIAGE_JSONL_PREFIX = 'triage_result'
_TRIAGE_COUNTER_FILE = '.triage_counter.json'
_WORKFLOW_CONFIG_PATH = os.path.expanduser('~/.flocks/plugins/workflows/stream_alert_triage/config.json')
_DEFAULT_SOC_DB_PATH = os.path.expanduser('~/.flocks/data/soc.db')


def _load_workflow_config():
    try:
        with open(_WORKFLOW_CONFIG_PATH, 'r', encoding='utf-8') as f:
            cfg = json.load(f)
        if isinstance(cfg, dict):
            return cfg
    except FileNotFoundError:
        pass
    except Exception as e:
        print(f'[triage_config] WARNING: failed to read {_WORKFLOW_CONFIG_PATH}: {e}')
    return {}


def _configured_value(config, key, default=None):
    if key in inputs:
        value = inputs.get(key)
        if value is not None and not (isinstance(value, str) and not value.strip()):
            return value
    return config.get(key, default)


def _input_bool(value, default=False):
    if value is None:
        return default
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    text = str(value).strip().lower()
    if text in {'1', 'true', 'yes', 'y', 'on'}:
        return True
    if text in {'0', 'false', 'no', 'n', 'off'}:
        return False
    return default


def _select_first_seen_soc_alerts(alerts):
    selected = []
    seen_dedup_keys = set()
    stats = {
        'input_rows': len(alerts),
        'first_seen_rows': 0,
        'skipped_not_first_seen_rows': 0,
        'skipped_missing_dedup_key_rows': 0,
        'skipped_repeated_dedup_key_rows': 0,
    }
    for alert in alerts:
        if not isinstance(alert, dict) or _input_bool(alert.get('is_duplicate'), True):
            stats['skipped_not_first_seen_rows'] += 1
            continue
        dedup_key = str(alert.get('dedup_key') or '').strip()
        if not dedup_key:
            stats['skipped_missing_dedup_key_rows'] += 1
            continue
        if dedup_key in seen_dedup_keys:
            stats['skipped_repeated_dedup_key_rows'] += 1
            continue
        seen_dedup_keys.add(dedup_key)
        selected.append(alert)
    stats['first_seen_rows'] = len(selected)
    return selected, stats


def _resolve_output_config():
    config = _load_workflow_config()
    raw_mode = str(_configured_value(config, 'triage_output_mode', 'soc_db') or 'soc_db').strip().lower()
    mode_alias = {
        'db': 'soc_db',
        'sqlite': 'soc_db',
        'sqlite_db': 'soc_db',
        'soc': 'soc_db',
        'json': 'jsonl',
        'file': 'jsonl',
        'files': 'jsonl',
        'off': 'none',
        'disabled': 'none',
    }
    requested_mode = mode_alias.get(raw_mode, raw_mode)
    if requested_mode not in {'soc_db', 'jsonl', 'both', 'none'}:
        print(f'[triage_config] WARNING: invalid triage_output_mode={raw_mode!r}; using soc_db')
        requested_mode = 'soc_db'

    legacy_jsonl = _input_bool(_configured_value(config, 'persist_triage_output', False), False)
    write_soc_db = requested_mode in {'soc_db', 'both'}
    write_jsonl = requested_mode in {'jsonl', 'both'}
    effective_mode = requested_mode
    if requested_mode == 'soc_db' and legacy_jsonl:
        write_jsonl = True
        effective_mode = 'both'
    if requested_mode == 'none':
        write_soc_db = False
        write_jsonl = False
        effective_mode = 'none'

    soc_db_path = os.path.expanduser(str(
        _configured_value(config, 'soc_db_path', _DEFAULT_SOC_DB_PATH) or _DEFAULT_SOC_DB_PATH
    ))
    jsonl_output_dir = _configured_value(config, 'jsonl_output_dir', '') or ''
    jsonl_output_dir = os.path.expanduser(str(jsonl_output_dir)) if jsonl_output_dir else ''
    return {
        'config_path': _WORKFLOW_CONFIG_PATH,
        'requested_mode': requested_mode,
        'mode': effective_mode,
        'write_soc_db': write_soc_db,
        'write_jsonl': write_jsonl,
        'soc_db_path': soc_db_path,
        'jsonl_output_dir': jsonl_output_dir,
    }


# ── Persisted JSONL output (optional; mirrors stream_alert_denoise layout) ─────
#
# Directory : ~/.flocks/workspace/workflows/stream_alert_triage/<YYYY-MM-DD>/
# Filename  : triage_result_NNN.jsonl  (3-digit zero-padded seq)
# Layout    : line 1 = {"_type":"file_header", ...}, subsequent lines = one
#             enriched_with_triage alert per line.
# Counter   : .triage_counter.json sidecar tracks (seq, count) so we don't
#             rescan every existing file on each run; auto-rolls over to a
#             new file when reaching MAX_RECORDS_PER_FILE.


def _triage_output_dir(configured_dir=''):
    """Return output directory for triage_result_*.jsonl."""
    if configured_dir:
        out_dir = configured_dir
        os.makedirs(out_dir, exist_ok=True)
        return out_dir
    from flocks.config import Config
    flocks_root = Config().get_global().data_dir.parent
    date_str = _datetime.datetime.now().strftime('%Y-%m-%d')
    out_dir = flocks_root / 'workspace' / 'workflows' / WORKFLOW_NAME / date_str
    out_dir.mkdir(parents=True, exist_ok=True)
    return str(out_dir)


def _triage_get_counter(out_dir):
    path = os.path.join(out_dir, _TRIAGE_COUNTER_FILE)
    try:
        with open(path, 'r', encoding='utf-8') as f:
            d = json.load(f)
        return int(d.get('seq', 0)), int(d.get('count', 0))
    except Exception:
        return 0, 0


def _triage_set_counter(out_dir, seq, count):
    path = os.path.join(out_dir, _TRIAGE_COUNTER_FILE)
    tmp = path + '.tmp'
    try:
        with open(tmp, 'w', encoding='utf-8') as f:
            json.dump({'seq': seq, 'count': count}, f)
        os.replace(tmp, path)
    except Exception:
        pass


def _triage_find_active_file(out_dir):
    """Locate the active (latest, not-yet-full) jsonl file; create if none."""
    seq, count = _triage_get_counter(out_dir)
    if seq > 0:
        path = os.path.join(out_dir, f'{_TRIAGE_JSONL_PREFIX}_{seq:03d}.jsonl')
        if os.path.exists(path):
            return path, count, seq
    import glob as _glob
    existing = sorted(_glob.glob(os.path.join(out_dir, _TRIAGE_JSONL_PREFIX + '_*.jsonl')))
    if not existing:
        return None, 0, 0
    latest = existing[-1]
    try:
        seq = int(os.path.basename(latest).replace(_TRIAGE_JSONL_PREFIX + '_', '').replace('.jsonl', ''))
    except ValueError:
        seq = len(existing)
    count = 0
    try:
        with open(latest, 'r', encoding='utf-8') as f:
            for line in f:
                if line.strip() and '"_type"' not in line:
                    count += 1
    except Exception:
        pass
    return latest, count, seq


def _triage_write_jsonl(out_dir, alerts, run_id, run_stats):
    """Append all alerts to today's triage_result_NNN.jsonl, rolling over at
    MAX_RECORDS_PER_FILE.  Returns the list of files that were written to."""
    now = _datetime.datetime.now()
    written       = []
    active_path, active_count, seq = _triage_find_active_file(out_dir)
    remaining     = list(alerts)
    while remaining:
        available = MAX_RECORDS_PER_FILE - active_count
        if available <= 0 or active_path is None:
            seq         += 1
            active_path  = os.path.join(out_dir, f'{_TRIAGE_JSONL_PREFIX}_{seq:03d}.jsonl')
            active_count = 0
            available    = MAX_RECORDS_PER_FILE
            header = {
                '_type':        'file_header',
                'created_at':   now.isoformat(),
                'date':         now.strftime('%Y-%m-%d'),
                'workflow':     WORKFLOW_NAME,
                'seq':          seq,
                'run_id':       run_id,
                'batch_total':  run_stats.get('total'),
                'batch_triaged':         run_stats.get('triaged'),
                'batch_followers_reused':run_stats.get('followers_reused'),
                'batch_cache_hit':       run_stats.get('cache_hit'),
                'batch_triage_failed':   run_stats.get('triage_failed'),
            }
            with open(active_path, 'w', encoding='utf-8') as hf:
                hf.write(json.dumps(header, ensure_ascii=False) + '\n')
        batch     = remaining[:available]
        remaining = remaining[available:]
        with open(active_path, 'a', encoding='utf-8') as af:
            for alert in batch:
                af.write(json.dumps(alert, ensure_ascii=False) + '\n')
        active_count += len(batch)
        if active_path not in written:
            written.append(active_path)
        if remaining:
            active_path  = None
            active_count = 0
    if written:
        _triage_set_counter(out_dir, seq, active_count)
    return written


# ── SOC DB output (default) ───────────────────────────────────────────────────

def _ensure_soc_db_schema(conn):
    conn.execute("""
        CREATE TABLE IF NOT EXISTS alert_records (
            row_id TEXT PRIMARY KEY,
            record_id TEXT,
            asset_date TEXT NOT NULL,
            source_file TEXT NOT NULL,
            line_number INTEGER NOT NULL,
            event_time INTEGER,
            source_type TEXT,
            threat_name TEXT,
            dedup_key TEXT,
            is_duplicate INTEGER NOT NULL DEFAULT 0,
            record_json TEXT NOT NULL
        )
    """)
    columns = {row[1] for row in conn.execute('PRAGMA table_info(alert_records)')}
    dedup_key_added = 'dedup_key' not in columns
    if dedup_key_added:
        conn.execute('ALTER TABLE alert_records ADD COLUMN dedup_key TEXT')

    unique_index_name = 'idx_alert_records_first_seen_dedup_key'
    indexes = list(conn.execute('PRAGMA index_list(alert_records)'))
    unique_index_ready = any(row[1] == unique_index_name and bool(row[2]) for row in indexes)
    conn.execute('CREATE INDEX IF NOT EXISTS idx_alert_records_duplicate ON alert_records(is_duplicate)')
    has_persisted_duplicates = conn.execute("""
        SELECT 1 FROM alert_records
        WHERE is_duplicate = 1
          AND dedup_key IS NOT NULL
          AND dedup_key <> ''
        LIMIT 1
    """).fetchone() is not None
    if not unique_index_ready or has_persisted_duplicates:
        if any(row[1] == unique_index_name for row in indexes):
            conn.execute(f'DROP INDEX {unique_index_name}')
        conn.execute("""
            UPDATE alert_records
            SET dedup_key = CASE
                WHEN json_valid(record_json)
                THEN NULLIF(TRIM(CAST(json_extract(record_json, '$.dedup_key') AS TEXT)), '')
                ELSE NULL
            END
            WHERE dedup_key IS NULL OR TRIM(dedup_key) = ''
        """)
        conn.execute("""
            UPDATE alert_records
            SET dedup_key = NULLIF(TRIM(dedup_key), '')
            WHERE dedup_key IS NOT NULL
        """)
        conn.execute("""
            DELETE FROM alert_records
            WHERE dedup_key IS NOT NULL
              AND dedup_key <> ''
              AND rowid NOT IN (
                  SELECT MIN(rowid)
                  FROM alert_records
                  WHERE dedup_key IS NOT NULL AND dedup_key <> ''
                  AND is_duplicate = 0
                  GROUP BY dedup_key
              )
        """)
        conn.execute(f"""
            CREATE UNIQUE INDEX {unique_index_name}
            ON alert_records(dedup_key)
            WHERE dedup_key IS NOT NULL AND dedup_key <> ''
        """)

    conn.execute('CREATE INDEX IF NOT EXISTS idx_alert_records_asset_date ON alert_records(asset_date)')
    conn.execute('CREATE INDEX IF NOT EXISTS idx_alert_records_event_time ON alert_records(event_time)')
    conn.execute('CREATE INDEX IF NOT EXISTS idx_alert_records_source_type ON alert_records(source_type)')
    conn.execute('CREATE INDEX IF NOT EXISTS idx_alert_records_threat_name ON alert_records(threat_name)')


def _event_time_value(alert):
    for key in ('time', 'event_time', 'timestamp', 'timestamp_real', 'occur_time', 'created_at'):
        value = alert.get(key)
        if value in (None, ''):
            continue
        if isinstance(value, (int, float)):
            ts = float(value)
            if ts > 100000000000:
                ts = ts / 1000.0
            return int(ts)
        text = str(value).strip()
        if not text:
            continue
        try:
            ts = float(text)
            if ts > 100000000000:
                ts = ts / 1000.0
            return int(ts)
        except Exception:
            pass
        normalized = text.replace('Z', '+00:00')
        try:
            return int(_datetime.datetime.fromisoformat(normalized).timestamp())
        except Exception:
            pass
        for fmt in ('%Y-%m-%d %H:%M:%S', '%Y/%m/%d %H:%M:%S', '%Y-%m-%d %H:%M', '%Y/%m/%d %H:%M'):
            try:
                return int(_datetime.datetime.strptime(text, fmt).timestamp())
            except Exception:
                continue
    return int(time.time())


def _asset_date_value(alert, event_time):
    value = alert.get('asset_date') or alert.get('_asset_date') or alert.get('date')
    if value:
        text = str(value).strip()
        if re.match(r'^\d{4}-\d{2}-\d{2}$', text):
            return text
    try:
        return _datetime.datetime.fromtimestamp(int(event_time)).strftime('%Y-%m-%d')
    except Exception:
        return _datetime.datetime.now().strftime('%Y-%m-%d')


def _source_type_value(alert):
    for key in ('source_type', '_source_type', 'data_source', 'log_type', 'vendor', 'device_type'):
        value = alert.get(key)
        if value not in (None, ''):
            return str(value)
    return ''


def _record_id_value(alert):
    for key in ('record_id', 'id', 'uuid', 'event_id', 'dedup_key'):
        value = alert.get(key)
        if value not in (None, ''):
            return str(value)
    return ''


def _stable_row_id(alert, source_file, line_number, event_time):
    existing = alert.get('row_id') or alert.get('_row_id')
    if existing:
        return str(existing)
    import hashlib as _hashlib
    basis = {
        'record_id': _record_id_value(alert),
        'dedup_key': alert.get('dedup_key', ''),
        'time': event_time,
        'source_file': source_file,
        'line_number': line_number,
        'sip': alert.get('sip', ''),
        'sport': alert.get('sport', ''),
        'dip': alert.get('dip', ''),
        'dport': alert.get('dport', ''),
        'threat_rule_id': alert.get('threat_rule_id') or alert.get('rule_id') or '',
    }
    raw = json.dumps(basis, sort_keys=True, ensure_ascii=False)
    return _hashlib.sha256(raw.encode('utf-8')).hexdigest()


def _load_existing_soc_rows(conn, dedup_keys):
    existing = {}
    unique_keys = list(dict.fromkeys(str(key).strip() for key in dedup_keys if str(key).strip()))
    for start in range(0, len(unique_keys), 500):
        chunk = unique_keys[start:start + 500]
        placeholders = ','.join('?' for _ in chunk)
        rows = conn.execute(f"""
            SELECT row_id, record_id, asset_date, source_file, line_number,
                   event_time, source_type, threat_name, dedup_key,
                   is_duplicate, record_json
            FROM alert_records
            WHERE dedup_key IN ({placeholders})
        """, chunk)
        for row in rows:
            try:
                record = json.loads(row[10])
            except Exception:
                record = {}
            if not isinstance(record, dict):
                record = {}
            existing[row[8]] = {
                'row_id': row[0],
                'record_id': row[1],
                'asset_date': row[2],
                'source_file': row[3],
                'line_number': row[4],
                'event_time': row[5],
                'source_type': row[6],
                'threat_name': row[7],
                'record': record,
            }
    return existing


def _merge_triage_record(existing_record, incoming_record):
    merged = dict(existing_record) if isinstance(existing_record, dict) else {}
    triage_fields = (
        'has_dedup_key',
        'triage_source',
        'triage_status',
        'attack_verdict',
        'risk_level',
        'report_title',
        'triage_report',
        'attack_success',
        'triage_ms',
        'triage_error',
        '_triage_run_id',
        '_triage_persisted_at',
    )
    for key in triage_fields:
        if key in incoming_record:
            merged[key] = incoming_record[key]
        elif key in {'triage_ms', 'triage_error'}:
            merged.pop(key, None)
    return merged


def _triage_write_soc_db(db_path, alerts, run_id):
    import sqlite3

    db_dir = os.path.dirname(db_path)
    if db_dir:
        os.makedirs(db_dir, exist_ok=True)
    default_source_file = ''
    loaded_files = inputs.get('loaded_files') or []
    if isinstance(loaded_files, list) and len(loaded_files) == 1:
        default_source_file = str(loaded_files[0])

    persisted_at = _datetime.datetime.now().isoformat()
    candidates = []
    seen_dedup_keys = set()
    for idx, alert in enumerate(alerts, 1):
        if not isinstance(alert, dict):
            continue
        dedup_key = str(alert.get('dedup_key') or '').strip()
        if not dedup_key or dedup_key in seen_dedup_keys:
            continue
        seen_dedup_keys.add(dedup_key)
        record = dict(alert)
        record['dedup_key'] = dedup_key
        record['is_duplicate'] = False
        record['_triage_run_id'] = run_id
        record['_triage_persisted_at'] = persisted_at
        source_file = str(
            record.get('source_file')
            or record.get('_source_file')
            or record.get('file_path')
            or default_source_file
            or 'stream_alert_triage'
        )
        try:
            line_number = int(record.get('line_number') or record.get('_line_number') or idx)
        except Exception:
            line_number = idx
        event_time = _event_time_value(record)
        candidates.append({
            'row_id': _stable_row_id(record, source_file, line_number, event_time),
            'record_id': _record_id_value(record),
            'asset_date': _asset_date_value(record, event_time),
            'source_file': source_file,
            'line_number': line_number,
            'event_time': event_time,
            'source_type': _source_type_value(record),
            'threat_name': str(record.get('threat_name') or record.get('rule_name') or ''),
            'dedup_key': dedup_key,
            'record': record,
        })

    insert_rows = []
    update_rows = []
    with sqlite3.connect(db_path, timeout=30) as conn:
        conn.execute('BEGIN IMMEDIATE')
        _ensure_soc_db_schema(conn)
        existing_by_key = _load_existing_soc_rows(
            conn, [candidate['dedup_key'] for candidate in candidates],
        )
        for candidate in candidates:
            existing = existing_by_key.get(candidate['dedup_key'])
            if existing:
                merged_record = _merge_triage_record(existing['record'], candidate['record'])
                merged_record['dedup_key'] = candidate['dedup_key']
                merged_record['is_duplicate'] = False
                update_rows.append((
                    candidate['dedup_key'],
                    json.dumps(merged_record, ensure_ascii=False),
                    existing['row_id'],
                ))
                continue
            insert_rows.append((
                candidate['row_id'],
                candidate['record_id'],
                candidate['asset_date'],
                candidate['source_file'],
                candidate['line_number'],
                candidate['event_time'],
                candidate['source_type'],
                candidate['threat_name'],
                candidate['dedup_key'],
                0,
                json.dumps(candidate['record'], ensure_ascii=False),
            ))

        if insert_rows:
            conn.executemany("""
                INSERT INTO alert_records (
                    row_id, record_id, asset_date, source_file, line_number,
                    event_time, source_type, threat_name, dedup_key,
                    is_duplicate, record_json
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """, insert_rows)
        if update_rows:
            conn.executemany("""
                UPDATE alert_records
                SET dedup_key = ?, is_duplicate = 0, record_json = ?
                WHERE row_id = ?
            """, update_rows)
        conn.commit()

    persisted_rows = len(insert_rows) + len(update_rows)
    return {
        'path': db_path,
        'table': 'alert_records',
        'rows': persisted_rows,
        'inserted_rows': len(insert_rows),
        'updated_rows': len(update_rows),
    }


# ── LLM provider warm-up (avoid cold-start race in _parallel_4_branches) ──────
#
# Background: when this node starts, the LLM provider (e.g. threatbook-cn-llm)
# is lazy-initialized on the first call.  Inside `_parallel_4_branches` we
# submit 4 LLM calls to a ThreadPoolExecutor simultaneously; whichever one
# wins the race may race against provider registration and fail with
# "provider 'xxx' not exists" while subsequent calls succeed.  A single
# synchronous warm-up call before any concurrent fan-out forces the provider
# to finish registering on the main thread, eliminating the race entirely.
#
# Failure of the warm-up is non-fatal — we just log and continue.  The first
# real LLM call will still see the same error and surface it normally.

def _warmup_llm():
    """Force LLM provider lazy-init on the main thread before any fan-out."""
    t0 = time.time()
    try:
        llm.ask('ping')
        print(f'[triage] LLM provider warm-up OK in {round((time.time()-t0)*1000)}ms')
        return True
    except Exception as e:
        print(f'[triage] WARNING: LLM warm-up failed ({type(e).__name__}: '
              f'{str(e)[:200]}); proceeding anyway')
        return False


# ── Inline triage helpers (mirroring tdp_alert_triage docs version) ───────────

def _strip_think(text):
    return re.sub(r'<think>[\s\S]*?</think>', '', str(text or ''), flags=re.IGNORECASE).strip()


def _is_public_ip(value):
    try:
        ip_obj = ipaddress.ip_address(value)
    except Exception:
        return False
    return not (ip_obj.is_private or ip_obj.is_loopback or ip_obj.is_reserved
                or ip_obj.is_link_local or ip_obj.is_multicast or ip_obj.is_unspecified)


def _pick(*values):
    for v in values:
        if v not in (None, '', [], {}):
            return v
    return ''


def _parse_alert(alert_input):
    """Mirrors tdp_alert_triage.receive_alert. Supports three input shapes:
    nested TDP (net.http.url), flat TDP (net_http_url), normalized (req_http_url).
    """
    if isinstance(alert_input, str):
        try:
            alert_input = json.loads(alert_input)
        except Exception:
            alert_input = {}
    if isinstance(alert_input, list):
        alert_data = alert_input[0] if alert_input else {}
    elif isinstance(alert_input, dict) and isinstance(alert_input.get('data'), list):
        alert_data = alert_input.get('data', [])[0] if alert_input.get('data') else {}
    else:
        alert_data = alert_input if isinstance(alert_input, dict) else {}

    net    = alert_data.get('net', {}) or {}
    http   = net.get('http', {}) or {}
    threat = alert_data.get('threat', {}) or {}
    assets = alert_data.get('assets', {}) or {}

    src_ip = _pick(
        alert_data.get('attacker'), alert_data.get('external_ip'),
        net.get('src_ip'), net.get('flow_src_ip'),
        alert_data.get('net_real_src_ip'),
        alert_data.get('sip'), alert_data.get('src_ip'), alert_data.get('src'),
    )
    dst_ip = _pick(
        alert_data.get('victim'), alert_data.get('machine'),
        alert_data.get('server_ip'), net.get('dest_ip'), net.get('flow_dest_ip'),
        alert_data.get('net_dest_ip'),
        alert_data.get('dip'), alert_data.get('dst_ip'), alert_data.get('dst'),
    )
    src_port = _pick(
        net.get('src_port'), net.get('flow_src_port'),
        alert_data.get('external_port'), alert_data.get('net_src_port'),
        alert_data.get('sport'), alert_data.get('src_port'), 0,
    )
    dst_port = _pick(
        net.get('dest_port'), net.get('flow_dest_port'),
        alert_data.get('server_port'), alert_data.get('machine_port'),
        alert_data.get('net_dest_port'),
        alert_data.get('dport'), alert_data.get('dst_port'), 0,
    )
    protocol = _pick(
        net.get('app_proto'), net.get('type'), net.get('proto'),
        alert_data.get('net_app_proto'), alert_data.get('protocol'),
        alert_data.get('event_type'), 'TCP',
    )
    alert_type = _pick(
        threat.get('name'), alert_data.get('threat_name'),
        alert_data.get('vuln_name'),
        alert_data.get('alert_type'), threat.get('topic'),
        alert_data.get('type'), 'unknown',
    )
    severity = _pick(
        threat.get('severity'), alert_data.get('threat_severity'),
        alert_data.get('severity'), threat.get('level'),
        alert_data.get('level'), 'medium',
    )

    req_line   = _pick(http.get('reqs_line'),   alert_data.get('req_line'),   alert_data.get('net_http_reqs_line'))
    req_header = _pick(http.get('reqs_header'), alert_data.get('req_header'), alert_data.get('net_http_reqs_header'))
    req_body   = _pick(http.get('req_body'),    alert_data.get('req_body'),   alert_data.get('net_http_reqs_body'))
    resp_line  = _pick(http.get('resp_line'),   alert_data.get('rsp_line'),   alert_data.get('resp_line'),
                       alert_data.get('net_http_resp_line'))
    resp_header = _pick(http.get('resp_header'), alert_data.get('rsp_header'), alert_data.get('resp_header'),
                        alert_data.get('net_http_resp_header'))
    resp_body  = _pick(http.get('resp_body'),   alert_data.get('rsp_body'),   alert_data.get('resp_body'),
                       alert_data.get('net_http_resp_body'))
    status = _pick(http.get('status'), alert_data.get('http_status'),
                   alert_data.get('net_http_status'), alert_data.get('rsp_status_code'), 0)

    host = _pick(http.get('reqs_host'), alert_data.get('url_host'), http.get('domain'),
                 alert_data.get('req_host'), alert_data.get('net_http_reqs_host'), dst_ip)
    raw_url = _pick(http.get('raw_url'), http.get('url'),
                    alert_data.get('url_path'),
                    alert_data.get('net_http_url'), alert_data.get('req_http_url'),
                    alert_data.get('uri'))
    url = ''
    if host and raw_url:
        scheme = 'https' if net.get('is_https') else 'http'
        url = raw_url if str(raw_url).startswith(('http://', 'https://')) else f'{scheme}://{host}{raw_url}'
    elif raw_url and str(raw_url).startswith(('http://', 'https://')):
        url = raw_url
    elif raw_url:
        url = raw_url

    payload  = f'请求行: {req_line}\n请求头: {req_header}\n请求体: {req_body}'
    response = f'状态行: {resp_line}\n响应头: {resp_header}\n响应体: {resp_body}'
    threat_result = _pick(threat.get('result'), alert_data.get('threat_result'))
    threat_msg    = _pick(threat.get('msg'),    alert_data.get('threat_msg'))

    log_text = (
        f'[告警基本信息]\n'
        f'告警类型: {alert_type}\n严重级别: {severity}\n'
        f'源地址: {src_ip}:{src_port}\n目的地址: {dst_ip}:{dst_port}\n'
        f'协议: {protocol}\nURL: {url}\nHTTP状态码: {status}\n'
        f'TDP判定: {threat_result}\nTDP消息: {threat_msg}\n\n'
        f'[HTTP请求内容]\n{payload}\n\n'
        f'[HTTP响应内容]\n{response}'
    )

    vuln_text = '\n'.join(str(item) for item in [
        threat_msg, threat.get('topic', ''),
        alert_data.get('data', ''), url,
        json.dumps(threat.get('tag', []), ensure_ascii=False),
    ] if item)
    vuln_matches = sorted(set(re.findall(r'\b(?:CVE|CNVD|CNNVD|XVE)-[A-Za-z0-9._-]+\b', vuln_text, flags=re.I)))

    iocs = []
    for candidate in [src_ip, dst_ip]:
        if candidate:
            iocs.append({'type': 'ip', 'value': candidate})
    if url:
        iocs.append({'type': 'url', 'value': url})
    if host and not re.match(r'^\d{1,3}(?:\.\d{1,3}){3}(?::\d+)?$', str(host)):
        iocs.append({'type': 'domain', 'value': str(host).split(':')[0]})

    return {
        'src_ip': src_ip, 'dst_ip': dst_ip, 'src_port': src_port, 'dst_port': dst_port,
        'protocol': protocol, 'payload': payload, 'response': response,
        'url': url, 'status': status,
        'alert_type': alert_type, 'severity': severity,
        'vuln_id': vuln_matches[0] if vuln_matches else '',
        'vuln_candidates': vuln_matches,
        'threat_result': threat_result, 'threat_msg': threat_msg,
        'failed_by': threat.get('failed_by', []),
        'asset_ip': assets.get('ip', ''), 'asset_name': assets.get('name', []),
        'iocs': iocs, 'log_text': log_text,
    }


def _prepare_intel(parsed):
    """Mirrors tdp_alert_triage.prepare_intel. Pre-fetches IP/domain/URL threat intel
    and CVE info so the parallel LLM tasks have concrete context to consume.
    """
    iocs = parsed.get('iocs', [])
    intel_results = []
    seen = set()
    for ioc in iocs:
        ioc_type = ioc.get('type', '')
        ioc_value = str(ioc.get('value', '')).strip()
        key = (ioc_type, ioc_value)
        if not ioc_value or key in seen:
            continue
        seen.add(key)
        if ioc_type == 'ip':
            if not _is_public_ip(ioc_value):
                continue
            r = tool.run_safe('threatbook_ip_query', ip=ioc_value)
            if r['success']:
                intel_results.append({'source': 'threatbook', 'type': 'ip',
                                      'value': ioc_value, 'result': r['text']})
        elif ioc_type == 'domain':
            r = tool.run_safe('threatbook_domain_query', domain=ioc_value)
            if r['success']:
                intel_results.append({'source': 'threatbook', 'type': 'domain',
                                      'value': ioc_value, 'result': r['text']})
        elif ioc_type == 'url':
            r = tool.run_safe('threatbook_url_query', url=ioc_value)
            if r['success']:
                intel_results.append({'source': 'threatbook', 'type': 'url',
                                      'value': ioc_value, 'result': r['text']})

    vuln_info = {}
    vuln_id = parsed.get('vuln_id', '')
    if vuln_id:
        r = tool.run_safe('__mcp_vuln_query', vuln_id=vuln_id)
        if r['success']:
            try:
                obj = r.get('obj')
                if isinstance(obj, str):
                    obj = json.loads(obj)
                vuln_info = obj if isinstance(obj, dict) else {'raw_result': r.get('text', '')}
            except Exception:
                vuln_info = {'raw_result': r.get('text', '')}

    intel_content = '\n'.join(
        f"[{i['source']}/{i['type']}] {i['value']}\n{i['result']}" for i in intel_results
    ) or '（无可用情报数据）'
    vuln_content = (
        json.dumps(vuln_info, ensure_ascii=False, indent=2)
        if vuln_info else '（无可用漏洞情报数据）'
    )
    return intel_results, intel_content, vuln_info, vuln_content


# ── 4 LLM analyses (the parallel branches from tdp_alert_triage) ─────────────

def _ask_llm(prompt):
    """Wrap ``llm.ask`` with the workflow-wide timeout + retry budget.

    Centralizing this avoids a hung provider request (no TCP timeout from
    upstream) from blocking a worker thread indefinitely. Any call that does
    not need bespoke parameters should go through here.
    """
    return llm.ask(
        prompt,
        timeout_s=LLM_CALL_TIMEOUT_S,
        max_retries=LLM_CALL_MAX_RETRIES,
    )


def _llm_survey(log_text, intel_content):
    prompt = f'''你是一个专业的Web日志分析专家。请总结以下IP的情报数据中的空间测绘信息。
1. 如果该IP没有测绘信息，则不列出。
2. 如果IP有测绘信息，则以简短的语言对该IP的测绘信息进行总结，关键说明ip的标签和测绘信息显示有哪些服务或者应用资产。
3. 多个IP的测绘信息以无序列表显示，每个ip数据描述占一行数据。
4. 不需要生成其他额外的补充信息。

## 情报参考信息
{intel_content}

## 用户的原始输入日志
{log_text}
'''
    return _strip_think(_ask_llm(prompt))


def _llm_cve_related(log_text):
    prompt = f'''请从以下的日志数据中提取漏洞编号。
要求：
1. 仅从日志文本中识别漏洞编号，不要做任何推测。
2. 如果日志中存在漏洞编号，则用简短语言描述，如："日志中存在漏洞编号：CVE-****-****"。
3. 如果日志中不存在漏洞编号，则输出："日志中无关联漏洞情报"。

日志数据如下：
{log_text}
'''
    return _strip_think(_ask_llm(prompt))


def _llm_cve_info(log_text, vuln_content):
    prompt = f'''你是一个专业的Web日志分析专家。参考情报信息中的漏洞数据，简要说明关联的CVE漏洞信息。
1. 不要输出任何解释说明，只输出漏洞基本信息。不需要生成漏洞的处置建议或修复措施等。

## 情报参考信息
{vuln_content}

## 用户的原始输入日志
{log_text}
'''
    return _strip_think(_ask_llm(prompt))


def _llm_payload_analysis(log_text):
    prompt = f'''你是一个专业的Web日志分析专家。根据用户输入的日志进行攻击负载分析。
1. 首先分析日志中是否包含攻击负载，并给出判定依据。
2. 不要进行攻击意图分析、攻击影响分析。
3. 用简短的语言在一段话中进行描述。

## 用户的原始输入日志:
{log_text}
'''
    return _strip_think(_ask_llm(prompt))


def _parallel_4_branches(parsed, intel_content, vuln_content):
    """4 LLM analyses run in parallel — keeps tdp_alert_triage's fan-out structure."""
    log_text = parsed.get('log_text', '')
    with ThreadPoolExecutor(max_workers=4, thread_name_prefix='triage_branch') as pool:
        futs = {
            'survey_result':           pool.submit(_llm_survey, log_text, intel_content),
            'cve_related_result':      pool.submit(_llm_cve_related, log_text),
            'cve_info_result':         pool.submit(_llm_cve_info, log_text, vuln_content),
            'payload_analysis_result': pool.submit(_llm_payload_analysis, log_text),
        }
        out = {}
        for name, fut in futs.items():
            try:
                out[name] = fut.result()
            except Exception as e:
                print(f'[triage] WARNING: branch {name} failed: {e}')
                out[name] = ''
    return out


# ── Join-point LLM analyses (attack_analysis_result -> verdict -> title) ──────

def _llm_attack_analysis(log_text):
    prompt = f'''你是一名专业且经验丰富的网络安全分析师和Web日志分析专家，你对HTTP协议以及Web攻击有着深入的理解，并且你能够快速识别和应对各种网络威胁。你的任务是对提供的HTTP请求与响应内容进行详细的专业分析，并判断日志请求的攻击状态。

请严格遵循以下指令进行思考和分析：
1. 攻击状态只能从以下情况中选择一种：["攻击成功", "攻击失败", "攻击", "未知", "安全"]。
2. 从日志中提取出"HTTP请求内容"和"HTTP响应内容"。请注意，HTTP请求内容和HTTP响应内容是分开的，请不要混淆，有些日志中没有包含HTTP响应内容，请不要将HTTP请求内容和HTTP响应内容混淆。分析后请你记住哪些是HTTP请求内容，哪些是HTTP响应内容。
3. 请检查HTTP响应状态码，2xx或者3xx状态码都代表本次HTTP请求成功，4xx或者5xx状态码大多数情况下都代表请求失败，只有在请求成功的情况下才能对攻击是否成功进行后续判断。

各攻击状态的定义以及判定标准：
1. 攻击成功：
(1) 首先分析日志中是否含有清晰的"HTTP响应内容"，如果日志中没有"HTTP响应内容"，则肯定不属于攻击成功。
(2) 如果日志中未提供"HTTP响应内容"，即使HTTP请求内容中包含攻击者预期的结果，也不能判定为攻击成功。
(3) 从日志中提取出"HTTP请求内容"和"HTTP响应内容"。请深入分析"HTTP响应内容"，并判定其是否为"HTTP请求内容"攻击成功时的预期结果，这是判定攻击成功的强依据。请注意，HTTP响应码200仅表示网络连接成功，不代表攻击攻击成功。
(4) 分析HTTP请求内容和HTTP响应内容，只有当HTTP响应内容中明确包含攻击载荷在目标机器上成功执行的证据，并且HTTP请求内容中包含攻击载荷的特征，则判定为"攻击成功"。
(5) 请注意：攻击成功的判定必须包含HTTP响应内容。如果不包含HTTP响应内容，则肯定不属于攻击成功。
(6) 请注意：如果不包含HTTP响应内容，即使HTTP请求内容是攻击，这也不属于攻击成功。
2. 攻击失败：
(1) 分析HTTP请求内容和HTTP响应内容，如果HTTP响应内容中明确包含攻击载荷在目标机器上执行失败或者被阻止的证据，并且HTTP请求内容中包含攻击载荷的特征，则判定为"攻击失败"。
(2) 攻击失败的判定必须包含HTTP响应内容。如果不包含HTTP响应内容，则肯定不属于攻击失败。
3. 攻击：
(1) 在"HTTP请求内容"或"HTTP响应内容"中发现任何证明存在攻击意图的证据，即可判定为存在攻击行为。但如果不符合上述的攻击成功或者攻击失败的标准，则"攻击状态"为"攻击"。
(2) 请注意：如果日志中只提供了"HTTP请求内容"，且没有提供"HTTP响应内容"，且HTTP的请求内容分析中是包含攻击行为的，则"攻击状态"为"攻击"。
4. 未知：
(1) 如果不能100%确定HTTP通信的攻击结果，那么请在"攻击状态"处给出"未知"。
(2) 请注意：如果在你给的判定原因中存在"可能"等不确定词汇，都代表你不能对你的结论100%确定，那么请在"攻击状态"处给出"未知"。
5. 安全：
(1) 如果"HTTP请求内容"和"HTTP响应内容"中都没有任何攻击意图的证据，那么请在"攻击状态"处给出"安全"。

## 日志内容
{log_text}

## 输出要求
请按下列结构输出（中文）：
1. 攻击状态: [攻击成功/攻击失败/攻击/未知/安全]
2. 判定依据: 简要说明请求与响应的关键证据
3. 详细分析: 不超过200字
'''
    return _strip_think(_ask_llm(prompt))


def _llm_attack_verdict(attack_analysis_result):
    prompt = f'''你是一个专业的Web日志分析专家。请据参考信息，直接输出攻击判定类别：
attack_success：表示攻击成功。
attack_failed：表示攻击失败。
attack：表示是日志内容是攻击。
unknown：表示未知。
benign：是安全。
不额外输出任何其他信息，包括解释、判定依据等。

## 日志分析结果:
{attack_analysis_result}
'''
    raw = _strip_think(_ask_llm(prompt)).strip().lower()
    return next((v for v in VERDICT_LABELS if v in raw), 'unknown')


def _llm_report_title(alert_type, attack_verdict, attack_analysis_result):
    prompt = f'''你是一个专业的Web日志分析专家。请基于以下分析结果，生成一份不超过 30 字的中文报告标题。
要求：
1. 标题必须能体现"攻击类型"或"攻击结果分析的结论"。
2. 不要带书名号、引号或其他标点。
3. 只输出标题本身，不要任何解释或说明。

## 攻击类型
{alert_type}

## 攻击判定
{attack_verdict}

## 攻击分析结果
{attack_analysis_result}
'''
    raw = _strip_think(_ask_llm(prompt)).strip()
    return raw.splitlines()[0].strip(' "\'《》[]【】') if raw else f'{alert_type} - {attack_verdict}'


def _clip_text(value, limit=3000):
    text = str(value or '').strip()
    if len(text) > limit:
        return text[:limit] + '\n...（已截断）'
    return text or '未提供'


def _fence_text(value):
    text = _clip_text(value, 6000)
    return text.replace('```', '``\\u200b`')


def _extract_tagged_triage_report(text):
    text = _strip_think(text)
    m = re.search(r'<triage_report\b[^>]*>[\s\S]*?</triage_report>', text, flags=re.I)
    return m.group(0).strip() if m else text.strip()


def _is_valid_triage_report(markdown):
    text = str(markdown or '')
    if not re.search(r'<triage_report\b[^>]*version=["\']soc\.triage\.markdown\.v1["\'][^>]*>', text, flags=re.I):
        return False
    if not re.search(r'</triage_report>', text, flags=re.I):
        return False
    for tag in TRIAGE_REPORT_TAGS:
        if not re.search(rf'<{tag}\b[^>]*>', text, flags=re.I):
            return False
        if not re.search(rf'</{tag}>', text, flags=re.I):
            return False
    return True


def _is_current_triage_fields(fields):
    if not isinstance(fields, dict):
        return False
    return _is_valid_triage_report(fields.get('triage_report'))


def _format_intel_brief(intel_results):
    if not intel_results:
        return '未查询到外部威胁情报。'
    lines = []
    for intel in intel_results[:6]:
        lines.append(f"- {intel.get('source', 'intel')} / {intel.get('type', 'ioc')}: {intel.get('value', '')} => {_clip_text(intel.get('result'), 500)}")
    return '\n'.join(lines)


def _build_default_tagged_triage_report(parsed, intel_results, vuln_info, branches,
                                        attack_analysis_result, attack_verdict,
