    payload = _fence_text(parsed.get('payload', ''))
    response = _fence_text(parsed.get('response', ''))
    url = parsed.get('url') or '未提供'
    threat_msg = parsed.get('threat_msg') or '未提供'
    status = parsed.get('status') or '未提供'
    survey = _clip_text(branches.get('survey_result'), 1500)
    cve_related = _clip_text(branches.get('cve_related_result'), 1500)
    cve_info = _clip_text(branches.get('cve_info_result'), 1500)
    payload_analysis = _clip_text(branches.get('payload_analysis_result'), 1500)
    attack_analysis = _clip_text(attack_analysis_result, 1500)
    intel_brief = _format_intel_brief(intel_results)
    vuln_brief = _clip_text(json.dumps(vuln_info, ensure_ascii=False, indent=2), 1800) if vuln_info else '未查询到漏洞详情。'

